function solve(n: number): boolean {
    let sum = 0;
    let product = 1;
    let num = n;
    while (num > 0) {
        const digit = num % 10;
        sum += digit;
        product *= digit;
        num = Math.floor(num / 10);
    }
    const total = sum + product;
    return n % total === 0;
}

